case "classify_failure": {
  const input = z.object({
    test_id: z.number().optional(),
    execution_id: z.number().optional(),
    test_name: z.string().optional(),
    test_file: z.string().optional(),
  }).parse(args)

  if (!input.test_id && (!input.execution_id || !input.test_name)) {
    return errorResponse("Must provide either test_id OR (execution_id + test_name)")
  }

  const classification = await db.getFailureClassification(orgId, {
    testId: input.test_id,
    executionId: input.execution_id,
    testName: input.test_name,
    testFile: input.test_file,
  })

  if (!classification) {
    return errorResponse("Test not found or no failure data available")
  }

  return jsonResponse({
    organization: authContext.organizationSlug,
    ...classification,
  })
}

solution.updated_handler:
case "classify_failure": {
  const input = z.object({
    test_id: z.number().optional(),
    execution_id: z.number().optional(),
    test_name: z.string().optional(),
    test_file: z.string().optional(),
    action_threshold: z.number().min(0).max(1).default(0.7),
  }).parse(args)

  if (!input.test_id && (!input.execution_id || !input.test_name)) {
    return errorResponse("Must provide either test_id OR (execution_id + test_name)")
  }

  const classification = await db.getFailureClassification(orgId, {
    testId: input.test_id,
    executionId: input.execution_id,
    testName: input.test_name,
    testFile: input.test_file,
  })

  if (!classification) {
    return errorResponse("Test not found or no failure data available")
  }

  // Add confidence interpretation
  const confidence = classification.confidence
  const confidence_level = confidence >= 0.8 ? "high" 
                          : confidence >= 0.6 ? "medium" 
                          : "low"

  const actionable = confidence >= input.action_threshold

  // Generate recommended action based on classification + confidence
  const recommended_action = getRecommendedAction(
    classification.suggested_classification,
    confidence_level
  )

  return jsonResponse({
    organization: authContext.organizationSlug,
    ...classification,
    confidence_level,
    actionable,
    action_threshold: input.action_threshold,
    recommended_action,
  })
}

// Helper function (add to tools.ts)
function getRecommendedAction(
  classification: "FLAKE" | "BUG" | "UNKNOWN",
  confidenceLevel: "high" | "medium" | "low"
): string {
  const actions: Record<string, Record<string, string>> = {
    FLAKE: {
      high: "Add @flaky annotation and create tracking issue for root cause investigation.",
      medium: "Review recent test history. Consider adding retry or @flaky annotation.",
      low: "Manually investigate failure pattern. May require more test runs for clarity.",
    },
    BUG: {
      high: "Create high-priority bug report. Test is consistently failing.",
      medium: "Create bug report and monitor for recurrence before prioritizing.",
      low: "Requires manual investigation. Failure pattern is unclear.",
    },
    UNKNOWN: {
      high: "Insufficient data for classification. Run more tests or manually investigate.",
      medium: "Insufficient data for classification. Run more tests or manually investigate.",
      low: "Insufficient data for classification. Run more tests or manually investigate.",
    },
  }

  return actions[classification]?.[confidenceLevel] 
    || "Manual investigation required."
}
